} catch {
  orderItems = [];
}

orderItems.forEach((item, idx) => {
  const name = item.name || item.display_name || 'Item';
  const qty = item.qty || item.quantity || 1;
  const price = item.price || item.line_total_cents || 0;
  const priceStr = (Number(price) / 100).toFixed(2);

  if (idx > 0) {
    itemsHtml += '<tr><td colspan="2" style="padding-top:10px;"></td></tr>';
  }

  itemsHtml += '<tr><td><strong>' + (qty > 1 ? qty + ' × ' : '') + name + '</strong></td><td style="text-align:right;">$' + priceStr + '</td></tr>';

  if (item.modifiers && Array.isArray(item.modifiers)) {
    item.modifiers.forEach(mod => {
      itemsHtml += '<tr><td style="padding-left:24px; font-style:italic; color:#555;">' + (mod.mod_name || mod.name) + '</td><td></td></tr>';
    });
  }

  if (item.notes && String(item.notes).trim()) {
    itemsHtml += '<tr><td colspan="2" style="padding-left:24px; font-style:italic; color:#555; padding-top:4px;">Notes: ' + item.notes + '</td></tr>';
  }
});

